          <circle class="donut-segment segment-todo" cx="21" cy="21" r="15.91549430918954" fill="transparent" stroke="#3b82f6" stroke-width="3" stroke-dasharray="{todoPercent} {todoRemainPercent}" stroke-dashoffset="100"></circle>
